#include "../testing_utils.h"

#include <xsf/trigamma.h>

#include <catch2/matchers/catch_matchers_floating_point.hpp>

#define REQUIRE_dCLOSE(a, b, rtol, atol)                                                                               \
    CAPTURE(a, b, rtol, atol);                                                                                         \
    REQUIRE_THAT(a, Catch::Matchers::WithinRel(b, rtol) || Catch::Matchers::WithinAbs(b, atol));

#define REQUIRE_zCLOSE(a, b, rtol, atol)                                                                               \
    CAPTURE(a, b, rtol, atol);                                                                                         \
    REQUIRE_THAT(                                                                                                      \
        std::real(a), Catch::Matchers::WithinRel(std::real(b), rtol) || Catch::Matchers::WithinAbs(std::real(b), atol) \
    );                                                                                                                 \
    REQUIRE_THAT(                                                                                                      \
        std::imag(a), Catch::Matchers::WithinRel(std::imag(b), rtol) || Catch::Matchers::WithinAbs(std::imag(b), atol) \
    );

